import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { bookingApi } from '../../api/bookingApi';
import BookingStatusBadge from './BookingStatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ErrorAlert from '../../components/common/ErrorAlert';

const BookingList = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const { user, isAdmin } = useAuth();

  useEffect(() => {
    loadBookings();
  }, []);

  const loadBookings = async () => {
    try {
      setLoading(true);
      let data;
      if (isAdmin()) {
        data = await bookingApi.getAllBookings({});
      } else {
        data = await bookingApi.getUserBookings(1); // In real app, get userId from user object
      }
      setBookings(data);
      setError(null);
    } catch (err) {
      setError('Failed to load bookings');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = async (id) => {
    if (window.confirm('Are you sure you want to cancel this booking?')) {
      try {
        await bookingApi.cancelBooking(id);
        loadBookings();
      } catch (err) {
        setError('Failed to cancel booking');
      }
    }
  };

  if (loading) return <LoadingSpinner />;
  if (error) return <ErrorAlert message={error} />;

  return (
    <div className="booking-list">
      <h1>{isAdmin() ? 'All Bookings' : 'My Bookings'}</h1>
      
      {bookings.length === 0 ? (
        <p className="no-data">No bookings found.</p>
      ) : (
        <table className="bookings-table">
          <thead>
            <tr>
              <th>Resource</th>
              <th>Date & Time</th>
              <th>Purpose</th>
              <th>Attendees</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {bookings.map((booking) => (
              <tr key={booking.id}>
                <td>
                  <strong>{booking.resourceName}</strong>
                  <br />
                  <small>ID: {booking.resourceId}</small>
                </td>
                <td>
                  {new Date(booking.startTime).toLocaleString()}
                  <br />
                  <small>to {new Date(booking.endTime).toLocaleString()}</small>
                </td>
                <td>{booking.purpose}</td>
                <td>{booking.expectedAttendees || '-'}</td>
                <td>
                  <BookingStatusBadge status={booking.status} />
                  {booking.rejectionReason && (
                    <div className="reason-tooltip">{booking.rejectionReason}</div>
                  )}
                </td>
                <td>
                  {(booking.status === 'PENDING' || booking.status === 'APPROVED') && (
                    <button
                      className="btn-cancel-small"
                      onClick={() => handleCancel(booking.id)}
                    >
                      Cancel
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default BookingList;
